    auth = _build_auth(auth_api_key_header, auth_api_key_query)
    headers = auth["headers"]
    params = dict(auth["params"])

    if not headers and "circle-token" not in params:
        pytest.skip("No authentication available (header/query). Authentication tests are handled separately.")

    endpoint = _build_endpoint(pipeline_id)
    # First page
    response = api_client.get(endpoint, headers=headers or None, params=params or None)
    if response.status_code != 200:
        # For non-2xx, validate default and skip follow
        _validate_response_schema(response, 400)  # any non-200 will route to 'default'
        pytest.skip(f"Initial request did not succeed (status={response.status_code}); skipping pagination follow-up.")

    _validate_response_schema(response, 200)

    try:
        body = response.json()
    except Exception:
        pytest.skip("Response not JSON; cannot continue pagination follow-up.")

    next_token = body.get("next_page_token")
    if not next_token:
        pytest.skip("No next_page_token provided; single page response.")

    # Second page using next_page_token
    follow_params = dict(params)
    follow_params["page-token"] = next_token
    response2 = api_client.get(endpoint, headers=headers or None, params=follow_params)
    # Status can be 200 or error per server behavior; validate accordingly
    if response2.status_code == 200:
        _validate_response_schema(response2, 200)
    else:
        _validate_response_schema(response2, 400)  # default


